/// Prepare the request before sending to backend
fn prepare_backend_request(mut req: Request, config: &BackendConfig) -> Request {
    // Set the host header to match the backend
    req.set_header(header::HOST, config.host);

    // Add forwarding headers
    if let Some(client_ip) = req.get_client_ip_addr() {
        req.set_header("X-Forwarded-For", client_ip.to_string());
    }
    req.set_header("X-Forwarded-Proto", "https");

    // Add a unique request ID for tracing
    let request_id = generate_request_id();
    req.set_header("X-Request-ID", &request_id);

    // Remove cookies for static content to improve caching
    if config.name == STATIC_BACKEND {
        req.remove_header(header::COOKIE);
    }

    req
}

/// Generate a simple request ID for tracing
fn generate_request_id() -> String {
    use std::time::{SystemTime, UNIX_EPOCH};
    let timestamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_nanos();
    format!("req-{:x}", timestamp)
}

/// Send request to the appropriate backend
fn send_to_backend(req: Request, backend_name: &str, config: &BackendConfig) -> Result<Response, Error> {
    // Use the pre-configured backend name registered in Fastly service configuration
    // The Backend struct references backends configured in fastly.toml or via API
    let backend = Backend::from_name(backend_name)?;

    match req.send(backend) {
        Ok(resp) => Ok(resp),
        Err(e) => {
            // Log the error
            eprintln!(
                "Backend {} ({}) error: {}",
                backend_name, config.host, e
            );

            // Return a 502 Bad Gateway response
            Ok(Response::from_status(StatusCode::BAD_GATEWAY)
                .with_header(header::CONTENT_TYPE, "application/json")
                .with_body(format!(
                    r#"{{"error": "Bad Gateway", "message": "Unable to reach backend service", "backend": "{}"}}"#,
                    backend_name
                )))
        }
    }
}

