/// Handle CORS preflight requests
fn handle_cors_preflight(req: &Request) -> Option<Response> {
    if req.get_method() != Method::OPTIONS {
        return None;
    }

    let origin = req
        .get_header_str("Origin")
        .unwrap_or_default()
        .to_string();

    // Validate allowed origins
    let allowed_origins = vec![
        "https://www.example.com",
        "https://app.example.com",
        "https://admin.example.com",
    ];

    if !allowed_origins.contains(&origin.as_str()) {
        return Some(Response::from_status(StatusCode::FORBIDDEN));
    }

    let mut resp = Response::from_status(StatusCode::NO_CONTENT);
    resp.set_header("Access-Control-Allow-Origin", &origin);
    resp.set_header(
        "Access-Control-Allow-Methods",
        "GET, POST, PUT, DELETE, PATCH, OPTIONS",
    );
    resp.set_header(
        "Access-Control-Allow-Headers",
        "Content-Type, Authorization, X-Request-ID",
    );
    resp.set_header("Access-Control-Max-Age", "86400");
    resp.set_header("Access-Control-Allow-Credentials", "true");

    Some(resp)
}

/// Add CORS headers to response
fn add_cors_headers(resp: &mut Response, req: &Request) {
    if let Some(origin) = req.get_header_str("Origin") {
        let allowed_origins = vec![
            "https://www.example.com",
            "https://app.example.com",
            "https://admin.example.com",
        ];

        if allowed_origins.contains(&origin) {
            resp.set_header("Access-Control-Allow-Origin", origin);
            resp.set_header("Access-Control-Allow-Credentials", "true");
            resp.set_header("Vary", "Origin");
        }
    }
}

/// Main entry point for the Compute@Edge service
#[fastly::main]
fn main(mut req: Request) -> Result<Response, Error> {
    // 1. Security: Sanitize incoming request
    if let Err(e) = SecurityConfig::sanitize_request(&mut req) {
        eprintln!("Security validation failed: {}", e);
        return Ok(Response::from_status(StatusCode::BAD_REQUEST)
            .with_header(header::CONTENT_TYPE, "application/json")
            .with_body(r#"{"error": "Bad Request", "message": "Request validation failed"}"#));
    }

    // 2. Security: Rate limiting check
    if !SecurityConfig::check_rate_limit(&req) {
        return Ok(Response::from_status(StatusCode::TOO_MANY_REQUESTS)
            .with_header(header::CONTENT_TYPE, "application/json")
            .with_header("Retry-After", "60")
            .with_body(r#"{"error": "Too Many Requests", "message": "Rate limit exceeded"}"#));
    }

    // 3. Handle health check endpoint
    let path = req.get_path().to_string();
    if path == "/health" || path == "/__health" {
        let mut resp = handle_health_check();
        SecurityConfig::add_security_headers(&mut resp);
        return Ok(resp);
    }

    // 4. Handle CORS preflight
    if let Some(mut cors_resp) = handle_cors_preflight(&req) {
        SecurityConfig::add_security_headers(&mut cors_resp);
        return Ok(cors_resp);
    }

    // 5. Security: Validate HTTP method for route
    let method = req.get_method().clone();
    if !SecurityConfig::is_method_allowed(&method, &path) {
        return Ok(Response::from_status(StatusCode::METHOD_NOT_ALLOWED)
            .with_header(header::CONTENT_TYPE, "application/json")
            .with_header("Allow", "GET, HEAD")
            .with_body(r#"{"error": "Method Not Allowed"}"#));
    }

    // 6. Route the request to the appropriate backend
    let (backend_name, backend_config) = Router::route(&req);

    // 7. Log routing decision
    println!(
        "Routing {} {} -> backend={} host={} port={} tls={}",
        method,
        path,
        backend_name,
        backend_config.host,
        backend_config.port,
        backend_config.use_tls
    );

    // 8. Prepare the request for the backend
    let prepared_req = prepare_backend_request(req.clone_without_body(), &backend_config);

    // Reconstruct request with body if present
    let final_req = if method == Method::POST
        || method == Method::PUT
        || method == Method::PATCH
    {
        let body = req.into_body();
        let mut new_req = prepared_req;
        new_req.set_body(body);
        new_req
    } else {
        prepared_req
    };

    // 9. Send to backend and get response
    let mut resp = send_to_backend(final_req, backend_name, &backend_config)?;

    // 10. Add security headers to response
    SecurityConfig::add_security_headers(&mut resp);

    // 11. Add CORS headers if applicable
    add_cors_headers(&mut resp, &req);

    // 12. Add cache control headers for static content
    if backend_name == STATIC_BACKEND && resp.get_status().is_success() {
        resp.set_header(
            header::CACHE_CONTROL,
            "public, max-age=31536000, immutable",
        );
    }

    // 13. Add the request ID to the response for tracing
    if let Some(request_id) = req.get_header_str("X-Request-ID") {
        resp.set_header("X-Request-ID", request_id);
    }

    Ok(resp)
}

